import React, { useState } from 'react';

const Banner = () => {
  const [imageUrl, setImageUrl] = useState('');

  return (
    <section className="mb-8">
      <div className="relative w-full h-64 md:h-80 rounded-xl overflow-hidden bg-slate-100 dark:bg-slate-800">
        {imageUrl ? (
          <img src={imageUrl} alt="Banner" className="w-full h-full object-cover" />
        ) : (
          <label className="w-full h-full flex flex-col items-center justify-center cursor-pointer hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">
            <span className="material-symbols-outlined text-6xl text-slate-400 mb-2">add_photo_alternate</span>
            <span className="text-slate-500 font-medium">Nhấp để chọn hình ảnh banner</span>
            <input 
              type="file" 
              accept="image/*" 
              className="hidden" 
              onChange={(e) => {
                const file = e.target.files[0];
                if (file) {
                  setImageUrl(URL.createObjectURL(file));
                }
              }}
            />
          </label>
        )}
        {imageUrl && (
          <button 
            onClick={() => setImageUrl('')}
            className="absolute top-4 right-4 bg-red-500 text-white p-2 rounded-lg hover:bg-red-600 transition-colors"
          >
            <span className="material-symbols-outlined">delete</span>
          </button>
        )}
      </div>
    </section>
  );
};

export default Banner;
